#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	int a,b,c=0;
	cin>>a>>b;
    int i=a;
	for(;i<=b;i++){
		if((i%4==0&&i%100!=0||i%400==0)) {
        c++;
        }
	} 
	cout<<c<<endl;
	i=a;
    for(;i<=b;i++){
		if((i%4==0&&i%100!=0||i%400==0)) {
        c++;
        cout<<i<<" ";
        }
	} 
	return 0;
}
